import React, { Component } from "react";
import { Button, Icon, Tag, Card, Divider } from "antd";
import { connect } from "react-redux";
import Navigation from "../src/components/navigation";

class Projects extends Component {
  render() {
    const { Meta } = Card;

    return (
      <div>
        <div
          style={{
            display: "flex",
            justifyContent: "center",
            alignItems: "center",
            flexDirection: "column",
            height: "100vh",
            backgroundColor: this.props.batmode ? "black" : "white"
          }}
        >
          <div
            style={{
              fontWeight: "bold",
              fontSize: "4vw",
              color: this.props.batmode ? "white" : "black"
            }}
          >
            Projects
          </div>
          <div
            style={{
              display: "flex",
              flexDirection: "row",
              alignItems: "center",
              justifyContent: "space-around",
              width: "75vw"
            }}
          >
            <div style={{ width: "30vw" }}>
              <Tag style={{ fontSize: "0.8vw" }} color="magenta">
                Software
              </Tag>
              <div
                style={{
                  fontSize: "1.2vw",
                  fontWeight: "bold",
                  color: this.props.batmode ? "white" : "black"
                }}
              >
                DimeDrop.io 🏀
              </div>
              <Card
                style={{
                  backgroundColor: this.props.batmode ? "black" : "white"
                }}
              >
                <div
                  style={{
                    fontSize: "1vw",
                    color: this.props.batmode ? "white" : "black"
                  }}
                >
                  A decentralized fantasy basketball game where you can
                  buy/sell/trade cartoon animals and play then in
                  tournament-style leagues
                </div>

                <div style={{ marginTop: "1vw" }}>
                  <Tag style={{ fontSize: "0.8vw" }} color="green">
                    Node.js
                  </Tag>
                  <Tag style={{ fontSize: "0.8vw" }} color="orange">
                    Socket.io
                  </Tag>
                  <Tag style={{ fontSize: "0.8vw" }} color="blue">
                    Next.js
                  </Tag>
                  <Tag style={{ fontSize: "0.8vw" }} color="red">
                    Infura
                  </Tag>
                  <Tag style={{ fontSize: "0.8vw" }} color="cyan">
                    Loom
                  </Tag>
                </div>

                <div style={{ display: "flex", justifyContent: "flex-end" }}>
                  <Button
                    type="link"
                    style={{ fontSize: "0.8vw" }}
                    onClick={() => window.open("https://dimedrop.io", "_blank")}
                  >
                    Visit
                  </Button>
                </div>
              </Card>
            </div>
            <img
              style={{ width: "45vw" }}
              src={
                "https://s3.eu-west-3.amazonaws.com/jackieni.io/memes/dime.png"
              }
            />
          </div>
          <div
            style={{
              display: "flex",
              flexDirection: "row",
              alignItems: "center",
              justifyContent: "space-around",
              width: "75vw"
            }}
          >
            <img style={{ width: "30vw" }} src={""} />

            <div style={{ width: "30vw" }}>
              <Tag style={{ fontSize: "0.8vw" }} color="magenta">
                Software
              </Tag>
              <div
                style={{
                  fontSize: "1.2vw",
                  fontWeight: "bold",
                  color: this.props.batmode ? "white" : "black"
                }}
              >
                DimeDrop.io 🏀
              </div>
              <Card
                style={{
                  backgroundColor: this.props.batmode ? "black" : "white"
                }}
              >
                <div
                  style={{
                    fontSize: "1vw",
                    color: this.props.batmode ? "white" : "black"
                  }}
                >
                  A decentralized fantasy basketball game where you can
                  buy/sell/trade cartoon animals and play then in
                  tournament-style leagues
                </div>

                <div style={{ marginTop: "1vw" }}>
                  <Tag style={{ fontSize: "0.8vw" }} color="green">
                    Node.js
                  </Tag>
                  <Tag style={{ fontSize: "0.8vw" }} color="orange">
                    Socket.io
                  </Tag>
                  <Tag style={{ fontSize: "0.8vw" }} color="blue">
                    Next.js
                  </Tag>
                  <Tag style={{ fontSize: "0.8vw" }} color="red">
                    Infura
                  </Tag>
                  <Tag style={{ fontSize: "0.8vw" }} color="cyan">
                    Loom
                  </Tag>
                </div>

                <div style={{ display: "flex", justifyContent: "flex-end" }}>
                  <Button
                    type="link"
                    style={{ fontSize: "0.8vw" }}
                    onClick={() => window.open("https://dimedrop.io", "_blank")}
                  >
                    Visit
                  </Button>
                </div>
              </Card>
            </div>
          </div>
        </div>
      </div>
    );
  }
}

const mapStateToProps = state => {
  const { batmode } = state.theme;
  return { batmode };
};

export default connect(mapStateToProps)(Projects);
